import os, csv, re, sys
import numpy as np
from scipy.optimize import least_squares
sys.path.insert(0, '.')

data_root = '/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited'

def load_dataset(path):
    with open(path) as f:
        reader = csv.reader(f, delimiter='\t')
        header = next(reader)
        rows = [r for r in reader if r]
    ncols = len(header) - 1
    def parse_param(h):
        m = re.search(r'(\d+(?:\.\d+)?)\s*uM', h, re.IGNORECASE)
        if m: return float(m.group(1))
        m = re.search(r'(\d+(?:\.\d+)?)\s*mM', h, re.IGNORECASE)
        if m: return float(m.group(1))*1000
        return None
    parsed = [parse_param(h) for h in header[1:]]
    params = parsed if all(p is not None for p in parsed) else list(range(1, ncols+1))
    X, y = [], []
    for row in rows:
        if not row: continue
        t = float(row[0])
        for p, val in zip(params, row[1:]):
            if val and val.strip().lower() != 'nan':
                X.append([t, float(p)])
                y.append(float(val))
    return np.array(X), np.array(y)

def nmse(y_true, y_pred):
    if not np.all(np.isfinite(y_pred)): return float('inf')
    var = np.var(y_true)
    if var <= 0: return np.mean((y_true-y_pred)**2)
    return np.mean((y_true-y_pred)**2) / var

# Model E: c4/(1+exp(-c0*(x0 - c1/x1^c2))) + c3
def model_E(X, c):
    t, x1 = X[:,0], X[:,1]
    c0, c1, c2, c3, c4 = c
    half_time = c1 / (np.abs(x1)**c2 + 1e-30)
    arg = np.clip(-c0 * (t - half_time), -500, 500)
    return c4 / (1 + np.exp(arg)) + c3

datasets = []
for dirpath, _, filenames in os.walk(data_root):
    if 'fit.tsv' in filenames:
        datasets.append(os.path.join(dirpath, 'fit.tsv'))
datasets.sort()

nmses_E = []
bad_E = []
for p in datasets:
    name = p.split('non-inhibited/')[-1]
    try:
        X, y = load_dataset(p)
        t_range = X[:,0].max() - X[:,0].min() + 1e-10
        t_mid = X[:,0].mean()
        def resid_E(c):
            pred = model_E(X, c)
            if not np.all(np.isfinite(pred)): return np.full(len(y), 1e6)
            return pred - y
        r = least_squares(resid_E, [4.0/t_range, t_mid, 0.5, 0.0, 1.0], loss='soft_l1', max_nfev=500)
        n = nmse(y, model_E(X, r.x))
        nmses_E.append(n)
        if n > 0.1:
            bad_E.append((name, n))
    except Exception as e:
        nmses_E.append(float('inf'))
        bad_E.append((name, float('inf')))

print(f'Model E: mean_nmse={np.mean(nmses_E):.4f}, median={np.median(nmses_E):.4f}')
print(f'Datasets with nmse>0.1 ({len(bad_E)}):')
for name, n in sorted(bad_E, key=lambda x: -x[1])[:10]:
    print(f'  {n:.4f}  {name}')
" 2>/dev/null
